fix_patch:
diff --git c/lib/compress/zstd_compress.c i/lib/compress/zstd_compress.c
index 3a48e7dcd4..3449f75705 100644
--- c/lib/compress/zstd_compress.c
+++ i/lib/compress/zstd_compress.c
@@ -1465,10 +1465,20 @@ ZSTD_adjustCParams_internal(ZSTD_compressionParameters cPar,
     if (cPar.windowLog < ZSTD_WINDOWLOG_ABSOLUTEMIN)
         cPar.windowLog = ZSTD_WINDOWLOG_ABSOLUTEMIN;  /* minimum wlog required for valid frame header */

+    if (ZSTD_rowMatchFinderSupported(cPar.strategy)) {
+        U32 const maxRowHashLog = 28; /* 32 - ZSTD_ROW_HASH_TAG_BITS + min rowLog (4) */
+        if (cPar.hashLog > maxRowHashLog) {
+            cPar.hashLog = maxRowHashLog;
+        }
+    }
+
     if (mode == ZSTD_cpm_createCDict && ZSTD_CDictIndicesAreTagged(&cPar)) {
-        U32 const maxShortCacheHashLog = 32 - ZSTD_SHORT_CACHE_TAG_BITS;
-        if (cPar.hashLog > maxShortCacheHashLog) {
-            cPar.hashLog = maxShortCacheHashLog;
+        U32 const maxShortCacheLog = 32 - ZSTD_SHORT_CACHE_TAG_BITS;
+        if (cPar.hashLog > maxShortCacheLog) {
+            cPar.hashLog = maxShortCacheLog;
+        }
+        if (cPar.chainLog > maxShortCacheLog) {
+            cPar.chainLog = maxShortCacheLog;
         }
     }
